; EarthBound C1 Battle selected-item action resolver.
;
; Source-emission status:
; - Prototype level: build-candidate
; - Generated by tools/emit_linear_source_module.py from a state-aware
;   linear ROM decode, then intended for byte-equivalence validation.
;
; Source units covered:
; - C1:CE85..C1:CFC6 ResolveSelectedBattleItemAction

; ---------------------------------------------------------------------------
; External contracts used by this module
; - Input A points to a small battle item-selection record:
;   +0 actor/character id, +1 selected inventory slot, +2 action word,
;   +4 target/result byte, +5 actor byte.
; - The selected item id is resolved through C3:E977, then indexed into the
;   D5:5000 item configuration table with stride 0x27.
; - Item config byte +0x19 gates target resolution/usability behavior; item
;   config word +0x1D supplies the battle action id passed to C1:ADB4.

C1ADB4_DetermineBattleTargetting       = $ADB4
C08FF7_ResolveIndexedPointerOffset     = $C08FF7
C09251_MapTargetSelectionResult        = $C09251
C3E977_GetItemInCharacterInventorySlot = $C3E977
C458AB_GetCharacterItemUsabilityMask   = $C458AB

BattleItemSelectionActorId      = $0000
BattleItemSelectionSelectedSlot = $0001
BattleItemSelectionActionWord   = $0002
BattleItemSelectionTargetByte   = $0004
BattleItemSelectionActorEcho    = $0005

ItemConfigTableBaseLo       = $5000
ItemConfigTableBank         = $00D5
ItemConfigTableStride       = $0027
ItemConfigBattleUseMask     = $0019
ItemConfigUsabilityMask     = $001C
ItemConfigBattleActionWord  = $001D

DefaultBattleItemActionClass = $0002
FailedBattleItemActionClass  = $0003

; ---------------------------------------------------------------------------
; C1:CE85

C1CE85_ResolveSelectedBattleItemAction:
    rep #$31
    phd
    pha
    tdc
    adc.w #$FFEA
    tcd
    pla
    tay
    sty $14
    lda.w #$00FF
    sta $02
    lda BattleItemSelectionSelectedSlot,Y
    and.w #$00FF
    tax
    lda BattleItemSelectionActorId,Y
    and.w #$00FF
    jsl C3E977_GetItemInCharacterInventorySlot
    sta $12
    lda.w #ItemConfigTableBaseLo
    sta $06
    lda.w #ItemConfigTableBank
    sta $08
    ; D5:5000 item rows are 0x27 bytes; the resolved item id selects the row.
    lda $12
    ldy.w #ItemConfigTableStride
    jsl C08FF7_ResolveIndexedPointerOffset
    clc
    adc $06
    sta $06
    ldy $14
    sty $04
    inc $04
    inc $04
    ; Default record action class is 2 until a targetting path overrides it.
    lda.w #DefaultBattleItemActionClass
    ldx $04
    sta $0000,X
    tya
    inc A
    inc A
    inc A
    inc A
    sta $10
    sep #$20
    lda.b #$01
    sta ($10)
    rep #$20
    tya
    clc
    adc.w #$0005
    sta $0E
    sep #$20
    lda BattleItemSelectionActorId,Y
    sta ($0E)
    ; Byte +0x19 is the battle-use/category mask used by CoilSnake's item
    ; table and by this runtime resolver.
    ldy.w #ItemConfigBattleUseMask
    lda [$06],Y
    rep #$20
    and.w #$00FF
    sta $12
    and.w #$0030
    cmp.w #$0010
    beq C1CF10_ResolveSelectedBattleItemAction_LCF10
    cmp.w #$0020
    beq C1CF10_ResolveSelectedBattleItemAction_LCF10
    cmp.w #$0030
    beq C1CF52_ResolveSelectedBattleItemAction_LCF52
    jmp.w C1CFBE_ResolveSelectedBattleItemAction_LCFBE
C1CF10_ResolveSelectedBattleItemAction_LCF10:
    ; Ordinary battle-use paths read the action word at item row +0x1D and
    ; hand it to the shared D5:7B68 targetting resolver.
    lda.w #ItemConfigBattleActionWord
    clc
    adc $06
    sta $06
    ldy $14
    lda BattleItemSelectionActorId,Y
    and.w #$00FF
    tax
    lda [$06]
    jsr DETERMINE_TARGETTING
    sta $02
    and.w #$00FF
    bne C1CF33_ResolveSelectedBattleItemAction_LCF33
    lda.w #$0000
    jmp.w C1CFC2_ResolveSelectedBattleItemAction_LCFC2
C1CF33_ResolveSelectedBattleItemAction_LCF33:
    lda [$06]
    ldx $04
    sta $0000,X
    sep #$10
    ldy.b #$08
    lda $02
    jsl C09251_MapTargetSelectionResult
    sep #$20
    sta ($10)
    rep #$20
    lda $02
    sep #$20
    sta ($0E)
    bra C1CFBE_ResolveSelectedBattleItemAction_LCFBE
C1CF52_ResolveSelectedBattleItemAction_LCF52:
    ; The 0x30 lane first checks the character usability mask in item row
    ; +0x1C against C4:58AB[actor - 1].
    lda $12
    and.w #$000C
    beq C1CF5E_ResolveSelectedBattleItemAction_LCF5E
    cmp.w #$0004
    bne C1CFBE_ResolveSelectedBattleItemAction_LCFBE
C1CF5E_ResolveSelectedBattleItemAction_LCF5E:
    ldy $14
    lda BattleItemSelectionActorId,Y
    and.w #$00FF
    tax
    stx $12
    dex
    sep #$20
    ldy.w #ItemConfigUsabilityMask
    lda [$06],Y
    and C458AB_GetCharacterItemUsabilityMask,X
    rep #$20
    and.w #$00FF
    beq C1CFB6_ResolveSelectedBattleItemAction_LCFB6
    lda.w #ItemConfigBattleActionWord
    clc
    adc $06
    sta $06
    ldx $12
    lda [$06]
    jsr DETERMINE_TARGETTING
    sta $02
    and.w #$00FF
    bne C1CF97_ResolveSelectedBattleItemAction_LCF97
    lda.w #$0000
    bra C1CFC2_ResolveSelectedBattleItemAction_LCFC2
C1CF97_ResolveSelectedBattleItemAction_LCF97:
    lda [$06]
    ldx $04
    sta $0000,X
    sep #$10
    ldy.b #$08
    lda $02
    jsl C09251_MapTargetSelectionResult
    sep #$20
    sta ($10)
    rep #$20
    lda $02
    sep #$20
    sta ($0E)
    bra C1CFBE_ResolveSelectedBattleItemAction_LCFBE
C1CFB6_ResolveSelectedBattleItemAction_LCFB6:
    ; Failed usability leaves the selection record with action class 3.
    lda.w #FailedBattleItemActionClass
    ldx $04
    sta $0000,X
C1CFBE_ResolveSelectedBattleItemAction_LCFBE:
    rep #$20
    lda $02
C1CFC2_ResolveSelectedBattleItemAction_LCFC2:
    rep #$10
    pld
    rts
